def diversification_rule(model, c):
    return model.xprod[c] <= 0.20 * sum(model.xprod[cp] for cp in model.c)
model.diversification = Constraint(model.c, rule=diversification_rule)

def temp_share_rule(model, tm):
    return model.tlab[tm] <= 0.10 * (model.tlab[tm] + model.flab[tm])
model.temp_share = Constraint(model.tm, rule=temp_share_rule)

def land_balance_rule(model, p):
    return model.xcrop[p, 'good'] <= model.xcrop[p, 'medium'] + 2
model.land_balance = Constraint(model.p, rule=land_balance_rule)

def sales_div_rule(model, c):
    return model.sales[c] <= 0.30 * sum(model.sales[cp] for cp in model.c)
model.sales_div = Constraint(model.c, rule=sales_div_rule)
